#include <bits/stdc++.h>
using namespace std;

int main() {
    // 使用更大的数据量
    const int n = 150; // 选择一个合适的大小使程序运行约2秒
    vector<int> klo;

    // 输入数据
    for(int i = 0; i < n; i++){
        int t;
        // 为了方便测试，改用随机数而不是手动输入
        t = rand() % 10000;
        klo.push_back(t);
    }

    sort(klo.begin(), klo.end());

    // 添加O(n³)的计算来控制运行时间
    long long sum = 0;
    for(int i = 0; i < n; i++) {
        for(int j = 0; j < n; j++) {
            for(int k = 0; k < n; k++) {
                sum += (klo[i] * klo[j]) % klo[max(1, k)];
            }
        }
    }

    // 输出结果
    for(int i = 0; i < n; i++) {
        cout << klo[i] << " ";
    }
    cout << "\n最终计算结果：" << sum << endl;

    return 0;
}

